DROP TABLE IF EXISTS "host_permissions_master";
CREATE TABLE "host_permissions_master" (
  "host_permission_id" integer GENERATED BY DEFAULT AS IDENTITY,
  "host_id" int DEFAULT NULL,
  "type" int DEFAULT NULL ,
  "is_add" smallint NOT NULL DEFAULT '0' ,
  "is_view" smallint NOT NULL DEFAULT '0' ,
  "is_edit" smallint NOT NULL DEFAULT '0' ,
  "is_delete" smallint NOT NULL DEFAULT '0' ,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("host_permission_id")
);

